#include <stdio.h>

int add_int(int a, int b) { return a + b; }
float add_float(float a, float b) { return a + b; }

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a, b;
        float x, y;
        scanf("%d %d", &a, &b);
        scanf("%f %f", &x, &y);
        printf("%d %.3f\n", add_int(a, b), add_float(x, y));
    }
    return 0;
}

