import sys

def add_int(a, b):
    return a + b

def add_float(a, b):
    return a + b

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = int(next(it)); b = int(next(it))
        x = float(next(it)); y = float(next(it))
        out.append(f"{add_int(a, b)} {add_float(x, y):.3f}")
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

